// =======================================================================
// BEAM ANALYSIS ENGINE
// =======================================================================
const NUM_POINTS = 500;

function analyzeBeam(span, uniformLoads, pointLoads, E_ksi, I_in4, triangularLoads = []) {
  const L = span; // ft
  const n = NUM_POINTS;
  const dx = L / n;
  const x = Array.from({ length: n + 1 }, (_, i) => i * dx);

  // Compute shear and moment at each point using superposition
  const V = new Float64Array(n + 1);
  const M = new Float64Array(n + 1);

  // Process each uniform load: w plf from a to b
  for (const ul of uniformLoads) {
    const w = ul.w; // plf
    const a = ul.a; // ft start
    const b = ul.b; // ft end
    if (w === 0 || a >= b) continue;

    const totalForce = w * (b - a);
    const Rb = totalForce * (a + b) / (2 * L);
    const Ra = totalForce - Rb;

    for (let i = 0; i <= n; i++) {
      const xi = x[i];
      let v = Ra;
      let m = Ra * xi;

      if (xi > a) {
        const loadLen = Math.min(xi, b) - a;
        v -= w * loadLen;
        m -= w * loadLen * (xi - a - loadLen / 2);
      }

      V[i] += v;
      M[i] += m;
    }
  }

  // Process triangular loads: linearly varying from wStart to wEnd over [a, b]
  for (const tl of triangularLoads) {
    const { wStart, wEnd, a, b } = tl;
    if (a >= b) continue;
    const len = b - a;
    // Total force = (wStart + wEnd) / 2 * len
    const totalForce = (wStart + wEnd) / 2 * len;
    // Centroid from a: (len/3) * (wStart + 2*wEnd) / (wStart + wEnd)
    const centroid = a + (len / 3) * (wStart + 2 * wEnd) / (wStart + wEnd || 1);
    const Rb = totalForce * centroid / L;
    const Ra = totalForce - Rb;

    for (let i = 0; i <= n; i++) {
      const xi = x[i];
      let v = Ra;
      let m = Ra * xi;

      if (xi > a) {
        const xLocal = Math.min(xi, b) - a;
        // w(x) = wStart + (wEnd - wStart) * x / len
        // Integral of w from 0 to xLocal = wStart * xLocal + (wEnd - wStart) * xLocal^2 / (2 * len)
        const loadArea = wStart * xLocal + (wEnd - wStart) * xLocal * xLocal / (2 * len);
        // Centroid of loaded portion from a:
        // integral of w*x dx / loadArea
        const loadMoment = wStart * xLocal * xLocal / 2 + (wEnd - wStart) * xLocal * xLocal * xLocal / (3 * len);
        const loadCentroid = loadArea > 0 ? loadMoment / loadArea : xLocal / 2;
        v -= loadArea;
        m -= loadArea * (xi - a - loadCentroid);
      }

      V[i] += v;
      M[i] += m;
    }
  }

  // Process each point load: P at location d
  for (const pl of pointLoads) {
    const P = pl.P; // lb
    const d = pl.d; // ft location
    if (P === 0) continue;

    const Ra = P * (L - d) / L;

    for (let i = 0; i <= n; i++) {
      const xi = x[i];
      let v = Ra;
      let m = Ra * xi;

      if (xi > d) {
        v -= P;
        m -= P * (xi - d);
      }

      V[i] += v;
      M[i] += m;
    }
  }

  // Find max absolute values
  let maxV = 0, maxM = 0;
  for (let i = 0; i <= n; i++) {
    if (Math.abs(V[i]) > Math.abs(maxV)) maxV = V[i];
    if (Math.abs(M[i]) > Math.abs(maxM)) maxM = M[i];
  }

  // Compute deflection using conjugate beam / numerical integration
  // M/(EI) is the "load" on the conjugate beam
  // E in ksi = E * 1000 psi; I in in^4
  // M is in lb-ft; need consistent units
  // delta = integral of (M * x_bar) / (E*I) ... use double integration
  // Convert: M in lb-ft, E in psi (ksi*1000), I in in^4
  // M in lb-in = M_lb_ft * 12
  // EI in lb-in^2 = E_ksi * 1000 * I_in4

  const EI = E_ksi * 1000 * I_in4; // lb-in^2
  const dxIn = dx * 12; // inches

  // M/EI curvature at each point (using M in lb-in)
  const kappa = new Float64Array(n + 1);
  for (let i = 0; i <= n; i++) {
    kappa[i] = (M[i] * 12) / EI; // 1/in
  }

  // First integration: slope (theta)
  const theta = new Float64Array(n + 1);
  theta[0] = 0;
  for (let i = 1; i <= n; i++) {
    theta[i] = theta[i - 1] + (kappa[i - 1] + kappa[i]) / 2 * dxIn;
  }

  // Second integration: deflection (y)
  const y = new Float64Array(n + 1);
  y[0] = 0;
  for (let i = 1; i <= n; i++) {
    y[i] = y[i - 1] + (theta[i - 1] + theta[i]) / 2 * dxIn;
  }

  // Apply boundary conditions: y(0) = 0, y(L) = 0
  // Correct by subtracting linear interpolation
  const yL = y[n];
  const defl = new Float64Array(n + 1);
  let maxDefl = 0;
  for (let i = 0; i <= n; i++) {
    defl[i] = y[i] - (yL * i) / n;
    if (Math.abs(defl[i]) > Math.abs(maxDefl)) maxDefl = defl[i];
  }

  return {
    x: Array.from(x),
    V: Array.from(V),
    M: Array.from(M),
    defl: Array.from(defl),
    maxV: Math.abs(maxV),
    maxM: Math.abs(maxM),
    maxDefl: Math.abs(maxDefl),
  };
}

// =======================================================================
// DIAGRAM COMPONENT (D3-based)
// =======================================================================
function Diagram({ x, y, title, unit, color, capacityLine, fillColor, overlayX, overlayY, yTickInterval }) {
  const svgRef = useRef(null);
  const tooltipRef = useRef(null);
  const containerRef = useRef(null);
  const [dims, setDims] = useState({ width: 400, height: 200 });
  const hasOverlay = overlayX && overlayY && overlayY.length > 0;

  useEffect(() => {
    const ro = new ResizeObserver(entries => {
      for (const e of entries) {
        const w = e.contentRect.width;
        if (w > 50) setDims({ width: w, height: 200 });
      }
    });
    if (containerRef.current) ro.observe(containerRef.current);
    return () => ro.disconnect();
  }, []);

  useEffect(() => {
    if (!svgRef.current || !x || x.length === 0) return;

    const margin = { top: 28, right: 16, bottom: 32, left: 64 };
    const w = dims.width - margin.left - margin.right;
    const h = dims.height - margin.top - margin.bottom;

    const svg = d3.select(svgRef.current);
    svg.selectAll("*").remove();
    svg.attr("width", dims.width).attr("height", dims.height);

    const g = svg.append("g").attr("transform", `translate(${margin.left},${margin.top})`);

    // Compute y domain including overlay data
    let yMin = Math.min(0, d3.min(y));
    let yMax = Math.max(0, d3.max(y));
    if (hasOverlay) {
      yMin = Math.min(yMin, d3.min(overlayY));
      yMax = Math.max(yMax, d3.max(overlayY));
    }

    const spanLen = x[x.length - 1];
    const xScale = d3.scaleLinear().domain([0, spanLen]).range([0, w]);

    // Snap y domain to tick interval if provided
    const pad = (yMax - yMin) * 0.12 || 1;
    let yDomMin = yMin - pad;
    let yDomMax = yMax + pad;
    if (yTickInterval) {
      yDomMin = Math.floor(yDomMin / yTickInterval) * yTickInterval;
      yDomMax = Math.ceil(yDomMax / yTickInterval) * yTickInterval;
    }
    const yScale = d3.scaleLinear().domain([yDomMin, yDomMax]).range([h, 0]);

    // Zero line
    g.append("line")
      .attr("x1", 0).attr("x2", w)
      .attr("y1", yScale(0)).attr("y2", yScale(0))
      .attr("stroke", "#64748b").attr("stroke-width", 1)
      .attr("stroke-dasharray", "4,3");

    const isDeflection = unit === "in";

    // -- Exceedance highlight zones with % labels --
    if (hasOverlay) {
      const bandH = h / 8;
      const bandY = h - bandH;

      // Helper: interpolate capacity at a given x position
      const getCapAt = (xi) => {
        if (!overlayX || !overlayY) return 0;
        const idx = overlayX.findIndex(ox => ox >= xi);
        if (idx <= 0) return Math.abs(overlayY[0] || 0);
        const t = (xi - overlayX[idx-1]) / (overlayX[idx] - overlayX[idx-1] || 1);
        return Math.abs(overlayY[idx-1] + t * (overlayY[idx] - overlayY[idx-1]));
      };

      // Collect exceedance zones: [{start, end, maxDev}]
      const zones = [];
      let inExceed = false;
      let exceedStart = 0;
      let zoneMaxDev = 0;
      const step = Math.max(1, Math.floor(y.length / 500));

      for (let i = 0; i <= y.length; i += (i < y.length ? step : 0)) {
        if (i >= y.length) i = y.length - 1;
        const xi = x[i];
        const demandVal = Math.abs(y[i]);
        const capVal = getCapAt(xi);
        const exceeds = demandVal > capVal * 1.001;
        const dev = demandVal - capVal;

        if (exceeds && !inExceed) {
          exceedStart = xi;
          zoneMaxDev = dev;
          inExceed = true;
        } else if (exceeds && inExceed) {
          zoneMaxDev = Math.max(zoneMaxDev, dev);
        } else if (!exceeds && inExceed) {
          zones.push({ start: exceedStart, end: xi, maxDev: zoneMaxDev });
          inExceed = false;
        }
        if (i === y.length - 1) {
          if (inExceed) zones.push({ start: exceedStart, end: xi, maxDev: zoneMaxDev });
          break;
        }
      }

      // Draw zones with deviation value labels
      for (const zone of zones) {
        const zx1 = xScale(zone.start);
        const zx2 = xScale(zone.end);
        const zw = Math.max(2, zx2 - zx1);
        g.append("rect")
          .attr("x", zx1).attr("y", bandY)
          .attr("width", zw).attr("height", bandH)
          .attr("fill", "#ef4444").attr("opacity", 0.15).attr("rx", 2);
        // Format deviation value based on unit
        const devLabel = isDeflection
          ? "+" + zone.maxDev.toFixed(3) + " in"
          : "+" + Math.round(zone.maxDev).toLocaleString() + " " + unit;
        g.append("text")
          .attr("x", zx1 + zw / 2).attr("y", bandY + bandH / 2 + 3.5)
          .attr("text-anchor", "middle")
          .attr("fill", "#ef4444").attr("font-size", "9px").attr("font-weight", 700)
          .text(devLabel);
      }
    }

    // -- Overlay curve (capacity) --
    if (hasOverlay) {
      const overlayLine = d3.line()
        .x((_, i) => xScale(overlayX[i]))
        .y(d => yScale(d))
        .curve(d3.curveMonotoneX);

      const overlayArea = d3.area()
        .x((_, i) => xScale(overlayX[i]))
        .y0(yScale(0))
        .y1(d => yScale(d))
        .curve(d3.curveMonotoneX);

      g.append("path").datum(overlayY).attr("d", overlayArea)
        .attr("fill", "rgba(239,68,68,0.05)").attr("stroke", "none");

      g.append("path").datum(overlayY).attr("d", overlayLine)
        .attr("fill", "none").attr("stroke", "#ef4444")
        .attr("stroke-width", 1.5).attr("stroke-dasharray", "6,3").attr("opacity", 0.8);
    }

    // -- Primary area + line --
    const area = d3.area()
      .x((_, i) => xScale(x[i]))
      .y0(yScale(0))
      .y1(d => yScale(d))
      .curve(d3.curveMonotoneX);

    g.append("path").datum(y).attr("d", area)
      .attr("fill", fillColor || "rgba(59,130,246,0.12)").attr("stroke", "none");

    const line = d3.line()
      .x((_, i) => xScale(x[i]))
      .y(d => yScale(d))
      .curve(d3.curveMonotoneX);

    g.append("path").datum(y).attr("d", line)
      .attr("fill", "none").attr("stroke", color || "#3b82f6").attr("stroke-width", 2);

    // -- Axes --
    // X axis: 1 ft increments
    const xAxis = d3.axisBottom(xScale)
      .tickValues(d3.range(0, spanLen + 0.5, 1))
      .tickFormat(d => d % 5 === 0 || d === 0 || d === Math.round(spanLen) ? d + "'" : "");

    // Y axis: use provided interval or auto
    let yAxis;
    if (yTickInterval) {
      const ticks = [];
      for (let v = yDomMin; v <= yDomMax + yTickInterval * 0.01; v += yTickInterval) {
        ticks.push(Math.round(v * 1000) / 1000);
      }
      yAxis = d3.axisLeft(yScale).tickValues(ticks);
    } else {
      yAxis = d3.axisLeft(yScale).ticks(6);
    }

    // Format y-axis numbers
    if (isDeflection) {
      yAxis.tickFormat(d => d === 0 ? "0" : d.toFixed(3));
    } else {
      yAxis.tickFormat(d3.format(",.0f"));
    }

    const xAxisG = g.append("g").attr("transform", `translate(0,${h})`).call(xAxis);
    xAxisG.selectAll("text").attr("fill", "#94a3b8").attr("font-size", "9px");
    // Minor ticks (no label) get shorter
    xAxisG.selectAll(".tick").each(function(d) {
      const text = d3.select(this).select("text").text();
      if (!text) d3.select(this).select("line").attr("y2", 3);
    });

    const yAxisG = g.append("g").call(yAxis);
    yAxisG.selectAll("text").attr("fill", "#94a3b8").attr("font-size", "10px");

    g.selectAll(".domain").attr("stroke", "#334155");
    g.selectAll(".tick line").attr("stroke", "#334155");

    // -- Title + Legend --
    svg.append("text")
      .attr("x", margin.left + w / 2).attr("y", 14)
      .attr("text-anchor", "middle")
      .attr("fill", "#e2e8f0").attr("font-size", "12px").attr("font-weight", 600)
      .text(`${title} (${unit})`);

    if (hasOverlay) {
      const lx = 8;
      g.append("line").attr("x1", lx).attr("x2", lx + 18).attr("y1", -10).attr("y2", -10)
        .attr("stroke", "#ef4444").attr("stroke-width", 1.5).attr("stroke-dasharray", "4,2");
      g.append("text").attr("x", lx + 22).attr("y", -7)
        .attr("fill", "#ef4444").attr("font-size", "9px").text("Capacity");
      g.append("line").attr("x1", lx + 72).attr("x2", lx + 90).attr("y1", -10).attr("y2", -10)
        .attr("stroke", color || "#3b82f6").attr("stroke-width", 2);
      g.append("text").attr("x", lx + 94).attr("y", -7)
        .attr("fill", color || "#3b82f6").attr("font-size", "9px").text("Demand");
    }

    // -- Interactive crosshair (only if overlay) --
    if (hasOverlay) {
      const crossV = g.append("line").attr("y1", 0).attr("y2", h)
        .attr("stroke", "#94a3b8").attr("stroke-width", 0.8).attr("stroke-dasharray", "3,3").style("display", "none");
      const crossH = g.append("line").attr("x1", 0).attr("x2", w)
        .attr("stroke", "#94a3b8").attr("stroke-width", 0.8).attr("stroke-dasharray", "3,3").style("display", "none");

      const dotDemand = g.append("circle").attr("r", 4).attr("fill", color || "#3b82f6").attr("stroke", "#fff").attr("stroke-width", 1).style("display", "none");
      const dotCap = g.append("circle").attr("r", 4).attr("fill", "#ef4444").attr("stroke", "#fff").attr("stroke-width", 1).style("display", "none");

      const tooltip = g.append("g").style("display", "none");
      const tooltipBg = tooltip.append("rect").attr("rx", 5).attr("ry", 5).attr("fill", "#1e293b").attr("stroke", "#475569").attr("stroke-width", 0.5).attr("opacity", 0.95);
      const tooltipText1 = tooltip.append("text").attr("fill", "#94a3b8").attr("font-size", "10px").attr("font-weight", 500);
      const tooltipText2 = tooltip.append("text").attr("fill", color || "#3b82f6").attr("font-size", "10px").attr("font-weight", 600);
      const tooltipText3 = tooltip.append("text").attr("fill", "#ef4444").attr("font-size", "10px").attr("font-weight", 600);

      const fmtVal = isDeflection ? (v => v.toFixed(4) + " in") : (v => Math.round(v).toLocaleString() + " " + unit);

      // Bisector for finding closest data point
      const bisect = d3.bisector(d => d).left;

      const overlay = g.append("rect").attr("width", w).attr("height", h).attr("fill", "none").attr("pointer-events", "all").style("cursor", "crosshair");

      overlay.on("mousemove", function(event) {
        const [mx] = d3.pointer(event, this);
        const xVal = xScale.invert(mx);
        if (xVal < 0 || xVal > spanLen) return;

        // Find demand value
        const idx = bisect(x, xVal);
        const i0 = Math.max(0, idx - 1);
        const i1 = Math.min(x.length - 1, idx);
        const t = (x[i1] - x[i0]) > 0 ? (xVal - x[i0]) / (x[i1] - x[i0]) : 0;
        const demandVal = y[i0] + t * (y[i1] - y[i0]);

        // Find capacity value
        const ci = bisect(overlayX, xVal);
        const ci0 = Math.max(0, ci - 1);
        const ci1 = Math.min(overlayX.length - 1, ci);
        const ct = (overlayX[ci1] - overlayX[ci0]) > 0 ? (xVal - overlayX[ci0]) / (overlayX[ci1] - overlayX[ci0]) : 0;
        const capVal = overlayY[ci0] + ct * (overlayY[ci1] - overlayY[ci0]);

        const px = xScale(xVal);
        crossV.attr("x1", px).attr("x2", px).style("display", null);
        crossH.attr("y1", yScale(demandVal)).attr("y2", yScale(demandVal)).style("display", null);
        dotDemand.attr("cx", px).attr("cy", yScale(demandVal)).style("display", null);
        dotCap.attr("cx", px).attr("cy", yScale(capVal)).style("display", null);

        // Tooltip
        tooltip.style("display", null);
        const xLabel = "x = " + xVal.toFixed(1) + " ft";
        const dLabel = "Demand: " + fmtVal(demandVal);
        const cLabel = "Capacity: " + fmtVal(capVal);
        tooltipText1.text(xLabel).attr("x", 8).attr("y", 15);
        tooltipText2.text(dLabel).attr("x", 8).attr("y", 29);
        tooltipText3.text(cLabel).attr("x", 8).attr("y", 43);

        const tw = Math.max(xLabel.length, dLabel.length, cLabel.length) * 6.5 + 16;
        const th = 52;
        tooltipBg.attr("width", tw).attr("height", th);

        let tx = px + 12;
        if (tx + tw > w) tx = px - tw - 12;
        let ty = yScale(demandVal) - th - 8;
        if (ty < 0) ty = yScale(demandVal) + 12;
        tooltip.attr("transform", `translate(${tx},${ty})`);
      });

      overlay.on("mouseleave", function() {
        crossV.style("display", "none");
        crossH.style("display", "none");
        dotDemand.style("display", "none");
        dotCap.style("display", "none");
        tooltip.style("display", "none");
      });
    }

  }, [x, y, dims, title, unit, color, capacityLine, fillColor, overlayX, overlayY, yTickInterval]);

  return (
    <div ref={containerRef} style={{ width: "100%" }}>
      <svg ref={svgRef} />
    </div>
  );
}


// =======================================================================
// BEAM VISUALIZATION (SVG)
// =======================================================================
function BeamViz({ span, uniformLoads, pointLoads, triangularLoads = [] }) {
  const svgW = 500, margin = 44;
  const bw = svgW - 2 * margin;
  const scale = bw / span;
  const maxLoadH = 55;
  const minLoadH = 12;

  // Find max magnitude for scaling
  const allMags = [
    ...uniformLoads.filter(u => u.w > 0).map(u => u.w),
    ...triangularLoads.map(t => Math.max(t.wStart || 0, t.wEnd || 0)),
  ];
  const maxMag = Math.max(...allMags, 1);

  const scaleH = (mag) => {
    if (mag <= 0) return 0;
    return minLoadH + (mag / maxMag) * (maxLoadH - minLoadH);
  };

  // Height map for stacking (discretized buckets)
  const buckets = 200;
  const heightMap = new Float64Array(buckets);

  const getOffset = (aFt, bFt) => {
    const i0 = Math.max(0, Math.floor((aFt / span) * buckets));
    const i1 = Math.min(buckets - 1, Math.floor((bFt / span) * buckets));
    let mx = 0;
    for (let i = i0; i <= i1; i++) mx = Math.max(mx, heightMap[i]);
    return mx;
  };

  const addToMap = (aFt, bFt, h) => {
    const i0 = Math.max(0, Math.floor((aFt / span) * buckets));
    const i1 = Math.min(buckets - 1, Math.floor((bFt / span) * buckets));
    for (let i = i0; i <= i1; i++) heightMap[i] += h;
  };

  // Uniform loads with stacking
  const ulRender = uniformLoads.filter(u => u.w > 0 && u.b > u.a).map((ul, i) => {
    const h = scaleH(ul.w);
    const offset = getOffset(ul.a, ul.b);
    addToMap(ul.a, ul.b, h + 5);
    return { ...ul, h, offset, idx: i };
  });

  // Triangular loads with stacking
  const triRender = triangularLoads.filter(t => (t.wStart > 0 || t.wEnd > 0) && t.b > t.a).map((tl, i) => {
    const peakMag = Math.max(tl.wStart, tl.wEnd);
    const h = scaleH(peakMag);
    const offset = getOffset(tl.a, tl.b);
    addToMap(tl.a, tl.b, h + 5);
    return { ...tl, h, offset, idx: i };
  });

  // Point loads with stacking
  const plRender = pointLoads.filter(p => p.P > 0).map((pl, i) => {
    const offset = getOffset(Math.max(0, pl.d - 0.2), Math.min(span, pl.d + 0.2));
    const arrowH = Math.max(18, offset + 22);
    addToMap(Math.max(0, pl.d - 0.3), Math.min(span, pl.d + 0.3), arrowH + 12);
    return { ...pl, arrowH, idx: i };
  });

  // SVG height from max stack
  let globalMaxH = 0;
  for (let i = 0; i < buckets; i++) globalMaxH = Math.max(globalMaxH, heightMap[i]);
  const topPad = 24;
  const bottomPad = 22;
  const svgH = topPad + Math.max(globalMaxH, 35) + 6 + bottomPad;
  const by = topPad + Math.max(globalMaxH, 35) + 4;

  const colors = ["#3b82f6", "#8b5cf6", "#06b6d4", "#10b981", "#f59e0b"];

  return (
    <svg width="100%" viewBox={`0 0 ${svgW} ${svgH}`} style={{ maxWidth: svgW }}>
      {/* Beam line */}
      <line x1={margin} y1={by} x2={margin + bw} y2={by} stroke="#94a3b8" strokeWidth={3} />
      {/* Supports */}
      <polygon points={`${margin},${by + 2} ${margin - 8},${by + 16} ${margin + 8},${by + 16}`} fill="none" stroke="#f59e0b" strokeWidth={1.5} />
      <polygon points={`${margin + bw},${by + 2} ${margin + bw - 8},${by + 16} ${margin + bw + 8},${by + 16}`} fill="none" stroke="#f59e0b" strokeWidth={1.5} />

      {/* Uniform loads -- stacked & scaled */}
      {ulRender.map((ul) => {
        const x1 = margin + ul.a * scale;
        const x2 = margin + ul.b * scale;
        const baseY = by - 2 - ul.offset;
        const topY = baseY - ul.h;
        const col = colors[ul.idx % colors.length];
        const arrowCount = Math.max(2, Math.round((x2 - x1) / 20));
        return (
          <g key={`ul${ul.idx}`}>
            <rect x={x1} y={topY} width={x2 - x1} height={ul.h} fill={col} opacity={0.08} />
            <line x1={x1} y1={topY} x2={x2} y2={topY} stroke={col} strokeWidth={2} opacity={0.7} />
            <line x1={x1} y1={topY} x2={x1} y2={baseY} stroke={col} strokeWidth={0.7} opacity={0.35} />
            <line x1={x2} y1={topY} x2={x2} y2={baseY} stroke={col} strokeWidth={0.7} opacity={0.35} />
            {Array.from({ length: arrowCount }, (_, j) => {
              const ax = x1 + (j / (arrowCount - 1)) * (x2 - x1);
              return <line key={j} x1={ax} y1={topY + 2} x2={ax} y2={baseY} stroke={col} strokeWidth={1} markerEnd={`url(#arr${ul.idx % colors.length})`} />;
            })}
            <text x={(x1 + x2) / 2} y={topY - 3} textAnchor="middle" fill={col} fontSize="8" fontWeight={600}>{ul.w} plf</text>
          </g>
        );
      })}

      {/* Triangular loads -- stacked & scaled */}
      {triRender.map((tl) => {
        const x1 = margin + tl.a * scale;
        const x2 = margin + tl.b * scale;
        const baseY = by - 2 - tl.offset;
        const peak = Math.max(tl.wStart, tl.wEnd, 1);
        const startH = tl.h * (tl.wStart / peak);
        const endH = tl.h * (tl.wEnd / peak);
        const cnt = Math.max(2, Math.round((x2 - x1) / 22));
        return (
          <g key={`tri${tl.idx}`}>
            <polygon
              points={`${x1},${baseY} ${x1},${baseY - startH} ${x2},${baseY - endH} ${x2},${baseY}`}
              fill="rgba(125,211,252,0.12)"
              stroke="#7dd3fc"
              strokeWidth={1.2}
            />
            {Array.from({ length: cnt }, (_, j) => {
              const frac = j / (cnt - 1);
              const ax = x1 + frac * (x2 - x1);
              const ah = startH + (endH - startH) * frac;
              if (ah < 4) return null;
              return <line key={j} x1={ax} y1={baseY - ah + 2} x2={ax} y2={baseY} stroke="#7dd3fc" strokeWidth={0.8} markerEnd="url(#arrowCyan)" />;
            })}
            {tl.wStart >= tl.wEnd
              ? <text x={x1 + 2} y={baseY - startH - 3} fill="#7dd3fc" fontSize="8" fontWeight={600}>drift {Math.round(tl.wStart)} plf</text>
              : <text x={x2 - 2} y={baseY - endH - 3} textAnchor="end" fill="#7dd3fc" fontSize="8" fontWeight={600}>drift {Math.round(tl.wEnd)} plf</text>
            }
          </g>
        );
      })}

      {/* Point loads -- stacked */}
      {plRender.map((pl) => {
        const px = margin + pl.d * scale;
        const tipY = by - 2;
        const topY = tipY - pl.arrowH;
        return (
          <g key={`pl${pl.idx}`}>
            <line x1={px} y1={topY} x2={px} y2={tipY} stroke="#f43f5e" strokeWidth={2} markerEnd="url(#arrowRed)" />
            <text x={px} y={topY - 4} textAnchor="middle" fill="#f43f5e" fontSize="9" fontWeight={600}>{pl.P} lb</text>
          </g>
        );
      })}

      {/* Span label */}
      <text x={margin + bw / 2} y={by + 16} textAnchor="middle" fill="#94a3b8" fontSize="10">{span} ft</text>

      <defs>
        {colors.map((c, i) => (
          <marker key={i} id={`arr${i}`} markerWidth="6" markerHeight="6" refX="3" refY="6" orient="auto">
            <path d={`M0,0 L3,6 L6,0`} fill="none" stroke={c} strokeWidth="1" />
          </marker>
        ))}
        <marker id="arrowRed" markerWidth="6" markerHeight="6" refX="3" refY="6" orient="auto">
          <path d="M0,0 L3,6 L6,0" fill="none" stroke="#f43f5e" strokeWidth="1" />
        </marker>
        <marker id="arrowCyan" markerWidth="5" markerHeight="5" refX="2.5" refY="5" orient="auto">
          <path d="M0,0 L2.5,5 L5,0" fill="none" stroke="#7dd3fc" strokeWidth="0.8" />
        </marker>
      </defs>
    </svg>
  );
}

// =======================================================================
// CAUTION INPUT FIELD
// =======================================================================
function CautionInput({ label, value, defaultValue, onChange, unit, disabled }) {
  const isOverridden = defaultValue !== undefined && value !== defaultValue && !disabled;
  return (
    <div style={{ position: "relative", display: "flex", flexDirection: "column", gap: 2 }}>
      <label style={{ fontSize: 11, color: "#94a3b8", fontWeight: 500, display: "flex", alignItems: "center", gap: 4 }}>
        {label}
        {isOverridden && <span title="Manually overridden" style={{ fontSize: 14, cursor: "help" }}>(!)</span>}
      </label>
      <div style={{ display: "flex", alignItems: "center" }}>
        <input
          type="number"
          value={value}
          onChange={e => onChange(parseFloat(e.target.value) || 0)}
          disabled={disabled}
          style={{
            width: "100%",
            padding: "6px 8px",
            background: isOverridden ? "#422006" : "#1e293b",
            border: isOverridden ? "1px solid #f59e0b" : "1px solid #334155",
            borderRadius: 6,
            color: "#f1f5f9",
            fontSize: 13,
            outline: "none",
            fontFamily: "'JetBrains Mono', monospace",
          }}
        />
        {unit && <span style={{ fontSize: 11, color: "#64748b", marginLeft: 4, whiteSpace: "nowrap" }}>{unit}</span>}
      </div>
    </div>
  );
}


// =======================================================================
// OWSJ REINFORCEMENT CHECK -- TAB 3 (integrated from OWSJReinforcementCalc)
// =======================================================================

// --- Engineering helpers ------------------------------------------------------
const rodArea = (d) => Math.PI * d * d / 4;
const rodRx   = (d) => d / 4;

const ROD_SIZES = [
  { label: '1/4" ROD',  dia: 0.25  },
  { label: '3/8" ROD',  dia: 0.375 },
  { label: '1/2" ROD',  dia: 0.5   },
  { label: '5/8" ROD',  dia: 0.625 },
  { label: '3/4" ROD',  dia: 0.75  },
];

// AISC equal-leg angle properties (single angle, ea. side)
// A: in2, rx: geometric x-axis r.o.g. (in), rz: minor principal axis (in)
// L2x2 series: AISC 14th Ed. tabulated. Smaller sizes: analytical + fillet correction.
const ANGLE_SIZES = [
  { label: 'L2x2x3/8',          A: 1.360, rx: 0.593, rz: 0.370 },
  { label: 'L2x2x5/16',         A: 1.152, rx: 0.601, rz: 0.377 },
  { label: 'L2x2x1/4',          A: 0.938, rx: 0.609, rz: 0.384 },
  { label: 'L2x2x3/16',         A: 0.715, rx: 0.617, rz: 0.391 },
  { label: 'L2x2x1/8',          A: 0.484, rx: 0.626, rz: 0.398 },
  { label: 'L1-3/4x1-3/4x1/4',  A: 0.812, rx: 0.529, rz: 0.338 },
  { label: 'L1-3/4x1-3/4x3/16', A: 0.621, rx: 0.537, rz: 0.334 },
  { label: 'L1-1/2x1-1/2x1/4',  A: 0.688, rx: 0.449, rz: 0.293 },
  { label: 'L1-1/2x1-1/2x3/16', A: 0.527, rx: 0.457, rz: 0.288 },
  { label: 'L1-1/4x1-1/4x1/4',  A: 0.562, rx: 0.369, rz: 0.247 },
  { label: 'L1-1/4x1-1/4x3/16', A: 0.434, rx: 0.377, rz: 0.242 },
  { label: 'L1x1x1/8',          A: 0.234, rx: 0.304, rz: 0.192 },
];

// AISC 360-05 E5: equiv. KL/r for single angle connected through one leg
// Uses rx (geometric x-axis); capped at 200
const angleEquivKLr = (memberLen, rx) => {
  const Lr = memberLen / rx;
  return Lr <= 80 ? 72 + 0.75 * Lr : Math.min(32 + 1.25 * Lr, 200);
};

function computeResults(inputs) {
  const {
    span, depth,
    RE, dM,
    fp,
    deflLimit, Iunreinf, deflUnreinf,
    l1, l2, braced,
    webMemberType, webAngleIdx,
    webDia, webFy, webE, webFu, weldSize, weldLen, U,
    chordDia, chordFy, chordFu, chordE, chordWeldSpacing, chordU,
  } = inputs;

  const OMEGA_T = 1.67;
  const OMEGA_T2 = 2.00;   // for rupture term Fu.U.Ag / 2.00
  const OMEGA_C = 1.67;

  // -- SHEAR -------------------------------------------------------------------
  const shearReqd = RE > 0;

  const phi      = 90 - Math.atan(l1 / depth) * 180 / Math.PI;
  const alpha    = Math.atan(2 * depth / l2) * 180 / Math.PI;
  const phiRad   = phi   * Math.PI / 180;
  const alphaRad = alpha * Math.PI / 180;

  const TE = shearReqd ? RE / Math.sin(phiRad) : 0;
  const CE = shearReqd ? TE * Math.sin(phiRad) / Math.sin(alphaRad) : 0;

  // Member type: rod or angle (2 members, one each side)
  const useAngle   = webMemberType === 'angle';
  const angleProps = useAngle ? ANGLE_SIZES[webAngleIdx] : null;
  const webAg      = useAngle ? angleProps.A * 2 : rodArea(webDia) * 2;
  const FyAdj      = webFy - fp;

  // Tension: Pn/Omega_t = min( F'y.Ag / 1.67 ,  Fu.U.Ag / 2.00 )
  const webTensYield   = FyAdj * webAg / OMEGA_T;
  const webTensRupture = webFu * U * webAg / OMEGA_T2;
  const webTensCap     = Math.min(webTensYield, webTensRupture);

  // Weld: 0.6 . 60ksi(electrode) . 0.707 . weld_size . weld_length . 2
  const weldCapacity = 0.6 * 60 * 0.707 * weldSize * weldLen * 2;

  // Compression -- end web member
  const memberLen  = (l2 / 2) / Math.cos(alphaRad);
  // For rods: rx = d/4, KL per braced flag
  // For angles: AISC 360-05 E5 equiv. slenderness uses rx (geometric), no K factor needed
  const rx         = useAngle ? angleProps.rx : rodRx(webDia);
  const KL         = useAngle ? memberLen : (braced ? memberLen / 2 : memberLen);
  const KLr        = useAngle ? angleEquivKLr(memberLen, rx) : KL / rx;
  const LoverRx    = useAngle ? memberLen / rx : null;  // L/rx displayed for angles
  const Fe         = Math.PI * Math.PI * webE / (KLr * KLr);
  const Fcr        = Fe >= 0.44 * webFy
    ? webFy * Math.pow(0.658, webFy / Fe)
    : 0.877 * Fe;
  const webCompCap = Fcr * webAg / OMEGA_C;

  const webTensOK  = !shearReqd || webTensCap  >= TE;
  const weldTensOK = !shearReqd || weldCapacity >= TE;
  const webCompOK  = !shearReqd || webCompCap   >= CE;
  const weldCompOK = !shearReqd || weldCapacity >= CE;

  // -- MOMENT ------------------------------------------------------------------
  const momentReqd = dM > 0;
  const Deff       = depth / 12;
  const dP         = momentReqd ? dM / Deff : 0;

  const chordAg    = rodArea(chordDia) * 2;
  const chordRxVal = rodRx(chordDia);
  const chordKLr   = chordWeldSpacing / chordRxVal;
  const chordFe    = Math.PI * Math.PI * chordE / (chordKLr * chordKLr);
  const chordFcr   = chordFe >= 0.44 * chordFy
    ? chordFy * Math.pow(0.658, chordFy / chordFe)
    : 0.877 * chordFe;

  // Chord tension: min( Fy.Ag/1.67 ,  Fu.U.Ag/2.00 )
  const chordTensYield   = chordFy * chordAg / OMEGA_T;
  const chordTensRupture = chordFu * chordU * chordAg / OMEGA_T2;
  const chordTensCap     = Math.min(chordTensYield, chordTensRupture);
  const chordCompCap     = chordFcr * chordAg / OMEGA_C;

  const chordTensOK = !momentReqd || chordTensCap >= Math.abs(dP);
  const chordCompOK = !momentReqd || chordCompCap >= Math.abs(dP);

  // -- DEFLECTION --------------------------------------------------------------
  // I_added = 2 * ( 2*(pi.d4/64) + Ag*(D/2 - 0.5 - d/2)2 )
  //   d  = chord rod diameter (in)
  //   Ag = area of 2 rods (in2)
  //   D  = joist depth (in)
  //   0.5 = chord vertical offset (in)
  const Irod_self  = Math.PI * Math.pow(chordDia, 4) / 64;        // one rod self I
  const e          = depth / 2 - 0.5 - chordDia / 2;              // centroid offset from NA
  const Iadded     = 2 * (2 * Irod_self + chordAg * e * e);       // both chords (top+bottom)
  const Ireinf     = Iunreinf + Iadded;

  const deflReinf     = deflUnreinf * Iunreinf / Ireinf;
  const deflAllowable = (span * 12) / deflLimit;
  const deflOK        = deflReinf <= deflAllowable;
  const LoverDeflU    = Math.round((span * 12) / deflUnreinf);
  const LoverDeflR    = Math.round((span * 12) / deflReinf);

  const allOK = webTensOK && weldTensOK && webCompOK && weldCompOK
              && chordTensOK && chordCompOK
              && deflOK;

  return {
    RE, shearReqd,
    phi, alpha, TE, CE,
    webAg, FyAdj,
    webTensYield, webTensRupture, webTensCap, weldCapacity,
    memberLen, rx, KLr, LoverRx, useAngle, Fe, Fcr, webCompCap,
    webTensOK, weldTensOK, webCompOK, weldCompOK,
    dM, dP, momentReqd,
    chordAg, chordRxVal, chordKLr, chordFe, chordFcr,
    chordTensYield, chordTensRupture, chordTensCap, chordCompCap,
    chordTensOK, chordCompOK,
    deflReinf, deflAllowable, deflOK, LoverDeflU, LoverDeflR,
    Iadded, Ireinf,
    allOK,
  };
}

